{"settings":"{
    "security.workspace.trust.untrustedFiles": "open",
    "extensions.experimental.affinity": {
        "asvetliakov.vscode-neovim": 1
    },
    "workbench.iconTheme": "eq-material-theme-icons-darker",
    "workbench.colorTheme": "Hack The Box",
    "vs-kubernetes": {
        "vscode-kubernetes.helm-path-linux": "/home/zefuros/.local/state/vs-kubernetes/tools/helm/linux-amd64/helm",
        "vscode-kubernetes.kubectl-path-linux": "/home/zefuros/.local/state/vs-kubernetes/tools/kubectl/kubectl",
        "vscode-kubernetes.minikube-path-linux": "/home/zefuros/.local/state/vs-kubernetes/tools/minikube/linux-amd64/minikube"
    },
    "files.autoSave": "afterDelay",
    "yaml.schemas": {
        "file:///home/zefuros/.vscode/extensions/continue.continue-1.2.11-linux-x64/config-yaml-schema.json": [
            ".continue/**/*.yaml"
        ]
    },
    "redhat.telemetry.enabled": true,
    "explorer.confirmDelete": false,
    "continue.enableNextEdit": false,
    "continue.enableTabAutocomplete": true,
    "[dockercompose]": {
        "editor.insertSpaces": true,
        "editor.tabSize": 2,
        "editor.autoIndent": "advanced",
        "editor.quickSuggestions": {
            "other": true,
            "comments": false,
            "strings": true
        },
        "editor.defaultFormatter": "redhat.vscode-yaml"
    },
    "[github-actions-workflow]": {
        "editor.defaultFormatter": "redhat.vscode-yaml"
    }
}"}
